    84→func (d *pluginClient) CanQueryDataSource(ctx context.Context, uid string) (bool, error) {
    85→	user, err := identity.GetRequester(ctx)
    86→	if err != nil {
    87→		return false, err
    88→	}
    89→
    90→	requiredScope := "datasources:uid:" + uid
    91→	evaluate := accesscontrol.EvalPermission(datasources.ActionQuery, requiredScope)
    92→	return d.ac.Evaluate(ctx, user, evaluate)
    93→}
