    95→// this handles the special `--grafana--` data source
    96→func getGrafanaDataSourceSettings(ctx context.Context) (*backend.DataSourceInstanceSettings, error) {
    97→	user, err := identity.GetRequester(ctx)
    98→	if err != nil {
    99→		return nil, err
   100→	}
   101→
   102→	ds := grafanads.DataSourceModel(user.GetOrgID())
   103→
   104→	decryptFunc := func(ds *datasources.DataSource) (map[string]string, error) {
   105→		// we do not need to handle any secrets
   106→		return nil, nil
   107→	}
   108→
   109→	return adapters.ModelToInstanceSettings(ds, decryptFunc)
   110→}
