   112→func (d *pluginClient) QueryData(ctx context.Context, req data.QueryDataRequest) (*backend.QueryDataResponse, error) {
   113→	queries, dsRef, err := data.ToDataSourceQueries(req)
   114→	if err != nil {
   115→		return nil, err
   116→	}
   117→	if dsRef == nil {
   118→		return nil, fmt.Errorf("expected single datasource request")
   119→	}
   120→
   121→	canQuery, err := d.CanQueryDataSource(ctx, dsRef.UID)
   122→	if err != nil {
   123→		return nil, err
   124→	}
   125→
   126→	if !canQuery {
   127→		return nil, k8sForbiddenError
   128→	}
   129→
   130→	var settings *backend.DataSourceInstanceSettings
   131→
   132→	// we need to special-case the "--grafana--" data source
   133→	if dsRef.UID == grafanads.DatasourceUID {
   134→		settings, err = getGrafanaDataSourceSettings(ctx)
   135→	} else {
   136→		// NOTE: this depends on uid unique across datasources
   137→		settings, err = d.pCtxProvider.GetDataSourceInstanceSettings(ctx, dsRef.UID)
   138→	}
   139→
   140→	if err != nil {
   141→		// there is no better way to differentiate between plugin-not-found and other-error
   142→		if errors.Is(err, datasources.ErrDataSourceNotFound) {
   143→			return nil, k8sNotFoundError
   144→		} else {
   145→			return nil, err
   146→		}
   147→	}
   148→
   149→	qdr := &backend.QueryDataRequest{
   150→		Queries: queries,
   151→	}
   152→	qdr.PluginContext, err = d.pCtxProvider.PluginContextForDataSource(ctx, settings)
   153→	if err != nil {
   154→		return nil, err
   155→	}
   156→
   157→	rsp, err := d.pluginClient.QueryData(ctx, qdr)
   158→	if err != nil {
   159→		return rsp, err
   160→	}
   161→	return rsp, err
   162→}
